import './ExpenseForm.css'

const ExpenseForm = () => {
    return (
        <form>
            <label htmlFor = 'newExpenseItemDesc'>New Expense</label>
            <input type = 'text' id = 'newExpenseItemDesc'></input>
            <label htmlFor = 'newExpenseItemDate'>New Expense Date</label>
            <input type = 'text' id = 'newExpenseItemDate'></input>
            <label htmlFor = 'newExpenseItemPrice'>New Expense Price</label>
            <input type = 'number' id = 'newExpenseItemPrice'></input>
        </form>
    )
}
export default ExpenseForm;
